// TypeScript implementation for Generic Interfaces
interface GenericInterfacesPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processGenericInterfaces(item: GenericInterfacesPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processGenericInterfaces({ id: 1, title: 'Generic Interfaces', status: 'active' }));

